#include <stdio.h>
#include <stdlib.h>

// Simple memoised recursion using unsigned long long (will overflow for large N, but follows the original template)
unsigned long long fib(int n, unsigned long long *memo) {
    if (n == 0) return 0ULL;
    if (n == 1) return 1ULL;
    if (memo[n] != ULLONG_MAX) return memo[n];
    memo[n] = fib(n - 1, memo) + fib(n - 2, memo);
    return memo[n];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        unsigned long long *memo = (unsigned long long *)malloc((n + 1) * sizeof(unsigned long long));
        for (int i = 0; i <= n; ++i) memo[i] = ULLONG_MAX; // sentinel for "not computed"
        printf("%llu\n", fib(n, memo));
        free(memo);
    }
    return 0;
}

